#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <stdint.h>
#include <omp.h>
#include "mix_kernels_cpu.h"
#include "version_info.h"

#define VECTOR_SIZE (32 * 1024 * 1024)

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return b == a; }

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *g_data, long total_elements) {
    const int stride = omp_get_max_threads();
    const int big_stride = total_elements / ELEMENTS_PER_THREAD;

    #pragma omp parallel
    {
        int idx = omp_get_thread_num() * ELEMENTS_PER_THREAD;
        if (idx + ELEMENTS_PER_THREAD > total_elements) return;

        T tmps[granularity];

        for(int k=0; k < fusion_degree; k++){
            for(int j=0; j < granularity; j++){
                tmps[j] = g_data[idx + j*stride + k*big_stride];

                int unroll_factor = TemperateUnroll ? 4 : 128;
                for(int i=0; i < compute_iterations; i++){
                    tmps[j] = mad(tmps[j], tmps[j], seed);
                }
            }

            T sum = conv_int<T>(0);
            for(int j=0; j < granularity; j = j + 2)
                sum = mad(tmps[j], tmps[j+1], sum);

            if( equal(sum, conv_int<T>(-1)) ) 
                g_data[idx + k*big_stride] = sum;
        }
    }
}

double get_time() {
    return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
    const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >(1, (short*)cd, size);
}

int out_config = 1;

template<unsigned int compute_iterations>
void runbench(double *cd, long size, bool doHalfs){
    const long compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
    const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
    const long long memoryoperations = size;

    double start, stop;
    float kernel_time_mad_sp, kernel_time_mad_dp, kernel_time_mad_hp, kernel_time_mad_int;

    // Float
    start = get_time();
    benchmark_func< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, size);
    stop = get_time();
    kernel_time_mad_sp = (float)((stop - start) * 1000.0);

    // Double
    start = get_time();
    benchmark_func< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0, cd, size);
    stop = get_time();
    kernel_time_mad_dp = (float)((stop - start) * 1000.0);

    kernel_time_mad_hp = 0.f;
    if( doHalfs ){
        start = get_time();
        benchmark_func< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, size);
        stop = get_time();
        kernel_time_mad_hp = (float)((stop - start) * 1000.0);
    }

    // Int
    start = get_time();
    benchmark_func< int, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true >(1, (int*)cd, size);
    stop = get_time();
    kernel_time_mad_int = (float)((stop - start) * 1000.0);

    printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        compute_iterations,
        ((double)computations)/((double)memoryoperations*sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
        ((double)2*computations)/((double)memoryoperations*sizeof(float)),
        kernel_time_mad_hp,
        ((double)2*computations)/kernel_time_mad_hp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(float))/kernel_time_mad_hp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(int)),
        kernel_time_mad_int,
        ((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

void mixbenchCPU(void *c, size_t size){
    const char *benchtype = "compute with global memory (block strided)";
    long elements = size / sizeof(double);

    printf("mixbench-cpu (%s)\n", VERSION_INFO);
    printf("Trade-off type:       %s\n", benchtype);
    printf("Elements per thread:  %d\n", ELEMENTS_PER_THREAD);
    printf("Thread fusion degree: %d\n", FUSION_DEGREE);

    double *cd = (double*)c;
    bool doHalfs = false;
    if( !doHalfs )
        printf("Warning:              Half precision computations are not supported\n");

    for(long i=0; i<elements; i++) cd[i] = 0.0;

    printf("----------------------------------------------------------------------------- CSV data -----------------------------------------------------------------------------\n");
    printf("Experiment ID, Single Precision ops,,,,              Double precision ops,,,,              Half precision ops,,,,                Integer operations,,, \n");
    printf("Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   GIOPS, GB/sec\n");

    runbench_warmup(cd, elements);

    runbench<0>(cd, elements, doHalfs);
    runbench<1>(cd, elements, doHalfs);
